$ErrorActionPreference = "Stop"
Set-StrictMode -Version Latest

function Write-Step {
    param([Parameter(Mandatory = $true)][string]$Message)
    Write-Host ""
    Write-Host "=== $Message ===" -ForegroundColor Cyan
}

function Assert-LastExitCode {
    param([Parameter(Mandatory = $true)][string]$Message)
    if ($LASTEXITCODE -ne 0) {
        throw $Message
    }
}

function Write-Base64Utf8File {
    param(
        [Parameter(Mandatory = $true)][string]$Path,
        [Parameter(Mandatory = $true)][string]$Base64
    )

    $Directory = Split-Path -Parent $Path
    New-Item -ItemType Directory -Path $Directory -Force | Out-Null
    $Bytes = [Convert]::FromBase64String($Base64)
    [System.IO.File]::WriteAllBytes($Path, $Bytes)
}

Write-Step "Locate Matrix RAG worktree"

$WorktreeRoot = "E:\Matrix-Worktrees"
$Candidates = @(
    Get-ChildItem -LiteralPath $WorktreeRoot -Directory -ErrorAction SilentlyContinue |
    Where-Object {
        (Test-Path -LiteralPath (Join-Path $_.FullName "package.json")) -and
        (Test-Path -LiteralPath (Join-Path $_.FullName "packages\database\prisma\schema.prisma")) -and
        ((Get-Content -LiteralPath (Join-Path $_.FullName "packages\database\prisma\schema.prisma") -Raw) -match "MATRIX_RAG_KNOWLEDGE_SCHEMA_START")
    } |
    Sort-Object LastWriteTime -Descending
)

if ($Candidates.Count -eq 0) {
    throw "Phase 2 is not complete. No valid worktree with the Matrix RAG Prisma schema was found."
}

$Worktree = $Candidates[0].FullName
Set-Location $Worktree
Write-Host "Worktree: $Worktree" -ForegroundColor Green
Write-Host "Branch:   $(git branch --show-current)" -ForegroundColor Green

Write-Step "Verify PostgreSQL and phase-2 tables"

docker info | Out-Null
Assert-LastExitCode "Docker Desktop is not running."

$ContainerName = "matrix-rag-postgres"
$Health = (docker inspect --format "{{if .State.Health}}{{.State.Health.Status}}{{else}}{{.State.Status}}{{end}}" $ContainerName 2>$null).Trim()
if ($Health -ne "healthy") {
    throw "PostgreSQL container is not healthy. Current state: $Health"
}

$env:DATABASE_URL = "postgresql://matrix:matrix_dev_change_me@127.0.0.1:55432/matrix_dev?schema=public"
$env:EMBEDDING_PROVIDER = "local-hash"

$RequiredTables = @(
    "KnowledgeDocument",
    "KnowledgeVersion",
    "KnowledgeChunk",
    "KnowledgeEmbedding",
    "EmbeddingJob"
)

foreach ($Table in $RequiredTables) {
    $Exists = (docker exec $ContainerName psql -U matrix -d matrix_dev -Atc "SELECT to_regclass('\"$Table\"') IS NOT NULL;").Trim()
    if ($Exists -ne "t") {
        throw "Required table $Table is missing. Run phase 2 successfully before phase 3."
    }
}

$VectorType = (docker exec $ContainerName psql -U matrix -d matrix_dev -Atc "SELECT format_type(a.atttypid, a.atttypmod) FROM pg_attribute a JOIN pg_class c ON c.oid = a.attrelid WHERE c.relname = 'KnowledgeEmbedding' AND a.attname = 'embedding' AND a.attnum > 0 AND NOT a.attisdropped;").Trim()
if ($VectorType -ne "vector(1024)") {
    throw "KnowledgeEmbedding.embedding must be vector(1024), found: $VectorType"
}

Write-Host "Database tables: verified" -ForegroundColor Green
Write-Host "Vector column:   $VectorType" -ForegroundColor Green

Write-Step "Back up files that will be modified"

$BackupRoot = "E:\Matrix-Backups\matrix-rag-phase3\$(Get-Date -Format 'yyyyMMdd-HHmmss')"
New-Item -ItemType Directory -Path $BackupRoot -Force | Out-Null

$AppModulePath = Join-Path $Worktree "apps\api\src\app.module.ts"
Copy-Item -LiteralPath $AppModulePath -Destination (Join-Path $BackupRoot "app.module.ts") -Force
Write-Host "Backup: $BackupRoot" -ForegroundColor Yellow

Write-Step "Write embedding, chunking, repository, service, and API files"

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\embedding-provider.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\local-hash-embedding.provider.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\openai-compatible-embedding.provider.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\embedding-provider.service.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\text-chunker.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\knowledge.repository.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\knowledge.service.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\knowledge.controller.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\src\\knowledge\\knowledge.module.ts"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\scripts\\test-rag.mjs"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\scripts\\rag-db-smoke.mjs"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "apps\\api\\.env.rag.example"
Write-Base64Utf8File -Path $TargetPath -Base64 ""

$TargetPath = Join-Path $Worktree "scripts\\start-rag-api.ps1"
Write-Base64Utf8File -Path $TargetPath -Base64 ""


Write-Step "Register KnowledgeModule in AppModule"

$AppModule = Get-Content -LiteralPath $AppModulePath -Raw

if ($AppModule -notmatch "import \{ KnowledgeModule \} from './knowledge/knowledge.module';") {
    $Anchor = "import { AuditModule } from './audit/audit.module';"
    if ($AppModule -notmatch [regex]::Escape($Anchor)) {
        throw "Unable to find the AppModule import anchor. Restore from: $BackupRoot"
    }
    $AppModule = $AppModule.Replace(
        $Anchor,
        "$Anchor`r`nimport { KnowledgeModule } from './knowledge/knowledge.module';"
    )
}

if ($AppModule -notmatch "(?m)^\s+KnowledgeModule,\s*$") {
    $ImportAnchor = "    PublicModule,"
    if ($AppModule -notmatch [regex]::Escape($ImportAnchor)) {
        throw "Unable to find the AppModule module-list anchor. Restore from: $BackupRoot"
    }
    $AppModule = $AppModule.Replace(
        $ImportAnchor,
        "$ImportAnchor`r`n    KnowledgeModule,"
    )
}

[System.IO.File]::WriteAllText(
    $AppModulePath,
    $AppModule,
    [System.Text.UTF8Encoding]::new($false)
)

Write-Step "Generate Prisma client and build API"

pnpm --filter @allinall/database db:generate
Assert-LastExitCode "Prisma client generation failed."

pnpm --filter @allinall/database build
Assert-LastExitCode "Database package build failed."

pnpm --filter @allinall/api build
Assert-LastExitCode "Matrix API build failed."

Write-Step "Run RAG unit tests"

node "apps/api/scripts/test-rag.mjs"
Assert-LastExitCode "Matrix RAG unit tests failed."

Write-Step "Run end-to-end database and vector search smoke test"

node "apps/api/scripts/rag-db-smoke.mjs"
Assert-LastExitCode "Matrix RAG database smoke test failed."

Write-Step "Stage phase-3 changes"

git add `
    "apps/api/src/knowledge" `
    "apps/api/src/app.module.ts" `
    "apps/api/scripts/test-rag.mjs" `
    "apps/api/scripts/rag-db-smoke.mjs" `
    "apps/api/.env.rag.example" `
    "scripts/start-rag-api.ps1"

$GitName = git config user.name
$GitEmail = git config user.email

if ($GitName -and $GitEmail) {
    git diff --cached --quiet
    if ($LASTEXITCODE -ne 0) {
        git commit -m "feat(ai): add RAG embeddings and semantic search"
        Assert-LastExitCode "Git commit failed."
    }
}
else {
    Write-Host "Git identity is not configured; changes are staged but not committed." -ForegroundColor Yellow
}

$VectorVersion = (docker exec $ContainerName psql -U matrix -d matrix_dev -Atc "SELECT extversion FROM pg_extension WHERE extname = 'vector';").Trim()
$DocumentCount = (docker exec $ContainerName psql -U matrix -d matrix_dev -Atc 'SELECT COUNT(*) FROM "KnowledgeDocument";').Trim()
$EmbeddingCount = (docker exec $ContainerName psql -U matrix -d matrix_dev -Atc 'SELECT COUNT(*) FROM "KnowledgeEmbedding" WHERE "embedding" IS NOT NULL;').Trim()

Write-Host ""
Write-Host "============================================" -ForegroundColor Green
Write-Host "MATRIX RAG PHASE 3 VERIFIED" -ForegroundColor Green
Write-Host "============================================" -ForegroundColor Green
Write-Host "Worktree:        $Worktree"
Write-Host "API build:       passed"
Write-Host "Unit tests:      passed"
Write-Host "Database smoke:  passed"
Write-Host "pgvector:        $VectorVersion"
Write-Host "Vector type:     $VectorType"
Write-Host "Documents:       $DocumentCount"
Write-Host "Embeddings:      $EmbeddingCount"
Write-Host "Provider:        local-hash"
Write-Host ""
Write-Host "Start API:" -ForegroundColor Cyan
Write-Host "& '$Worktree\scripts\start-rag-api.ps1'"
Write-Host ""
Write-Host "Search endpoint:" -ForegroundColor Cyan
Write-Host "POST http://127.0.0.1:4000/api/v1/knowledge/search"
Write-Host ""
Write-Host "Health endpoint:" -ForegroundColor Cyan
Write-Host "GET  http://127.0.0.1:4000/api/v1/knowledge/health"
